  `Lý do: ${item.reason_codes_csv || '—'}`,
  `Khách: ${item.contact_name}`,
  `SĐT: ${item.contact_phone}`,
  `Email: ${item.contact_email}`,
  `Hạn SLA: ${item.sla_due_at}`,
  '',
  item.recommended_action || 'Để chuyên gia HouseX tư vấn và giải thích rõ hồ sơ.',
];

const message = lines.join('\n').slice(0, 3900);
const token = $env.TELEGRAM_BOT_TOKEN || '';
const enabled = String($env.TELEGRAM_NOXH_ENABLED || 'true').toLowerCase() === 'true';

return [{
  json: {
    ...item,
    telegram_enabled: enabled && !!token && !!chat_id,
    telegram_chat_id: chat_id,
    telegram_message: message,
    telegram_priority: priority,
  },
}];

const item = $input.first().json;
if (!item.telegram_enabled) {
  return [{
    json: {
      ...item,
      telegram_sent: false,
      telegram_skip: item.telegram_skip || 'TELEGRAM_DISABLED',
    },
  }];
}

const token = $env.TELEGRAM_BOT_TOKEN || '';
const chatId = item.telegram_chat_id || '';

let tgRes;
try {
  tgRes = await this.helpers.httpRequest({
    method: 'POST',
    url: `https://api.telegram.org/bot${token}/sendMessage`,
    body: {
      chat_id: chatId,
      text: item.telegram_message,
      disable_web_page_preview: true,
    },
    json: true,
    timeout: 15000,
  });
} catch (e) {
  return [{
    json: {
      ...item,
      telegram_sent: false,
      telegram_error: (e.message || String(e)).slice(0, 200),
    },
  }];
}

return [{
  json: {
    ...item,
    telegram_sent: tgRes?.ok === true,
    telegram_message_id: tgRes?.result?.message_id || null,
  },
}];

const SECRET = $env.EVENTS_WEBHOOK_SECRET || '';
const headers = $input.first().json.headers || {};
const got = headers['x-events-secret'] || headers['X-Events-Secret'] || '';
if (SECRET && got !== SECRET) {
  throw new Error('Unauthorized: invalid EVENTS_WEBHOOK_SECRET');
}

const raw = $input.first().json;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const type = String(body.type || '').trim();

if (type !== 'lead.noxh_checked.detail') {
  return [{ json: { ok: true, skipped: true, path: 'detail', reason: 'NOT_DETAIL_EVENT', type } }];
}

const p = body.payload || {};
const leadId = String(p.leadId || '').trim();
if (!leadId) throw new Error('Validation: payload.leadId is required');

const s = p.situation || {};
const c = p.contact || {};
const now = body.sentAt || new Date().toISOString();

return [{
  json: {
    ok: true,
    skipped: false,
    path: 'detail',
    lead_id: leadId,
    tier: String(p.tier || ''),
    object_group: String(s.objectGroup || ''),
    marital_status: String(s.maritalStatus || ''),
    applicant_income: Number(s.applicantMonthlyIncome) || 0,
    spouse_income: Number(s.spouseMonthlyIncome) || 0,
    owns_home: s.ownsHomeInProvince === true,
    area_per_person: s.areaPerPersonSqm,
    intend_to_borrow: s.intendToBorrow === true,
    existing_debt: Number(s.existingMonthlyDebtPayment) || 0,
    card_limit: Number(s.creditCardLimitTotal) || 0,
    bad_debt: String(s.badDebtSelfOrSpouse || ''),
    timeframe: String(s.timeframe || ''),
    dti: s.dti != null ? Number(s.dti) : null,
    contact_name: String(c.name || '').slice(0, 80),
    contact_phone: String(c.phone || '').slice(0, 20),
    contact_email: String(c.email || '').slice(0, 120),
    evaluation_reasons: JSON.stringify(p.evaluationReasons || []).slice(0, 8000),
    credit_reasons: JSON.stringify(p.creditReasons || []).slice(0, 8000),
    next_steps: JSON.stringify(p.nextSteps || []).slice(0, 8000),
    rules_version: String(p.rulesVersion || ''),
    created_at: now,
  },
}];

const item = $input.first().json;
if (item.skipped) return [{ json: item }];

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const TAB = 'noxh_leads_detail';

const append_row = [
  item.lead_id,
  item.tier,
  item.object_group,
  item.marital_status,
  item.applicant_income,
  item.spouse_income,
  item.owns_home ? 'yes' : 'no',
  item.area_per_person ?? '',
  item.intend_to_borrow ? 'yes' : 'no',
  item.existing_debt,
  item.card_limit,
  item.bad_debt,
  item.timeframe,
  item.dti ?? '',
  item.evaluation_reasons,
  item.credit_reasons,
  item.next_steps,
  item.rules_version,
  item.contact_name,
  item.contact_phone,
  item.contact_email,
  item.created_at,
];

return [{
  json: {
    ...item,
    append_row,
    append_url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(`${TAB}!A:V`)}:append?valueInputOption=USER_ENTERED&insertDataOption=INSERT_ROWS`,
    append_body: { values: [append_row] },
  },
}];
